2	
3	function isNeighbor([ax, ay]: Cell, [bx, by]: Cell): boolean {
4	  if (ax === bx && ay === by) return false;
5	  return Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
6	}
7	
8	function countLiveNeighbors(cell: Cell, liveCells: readonly Cell[]): number {
9	  return liveCells.filter((other) => isNeighbor(cell, other)).length;
10	}
11	
12	export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
13	  return liveCells.filter((cell) => {
14	    const neighbors = countLiveNeighbors(cell, liveCells);
15	    return neighbors === 2 || neighbors === 3;
16	  });
17	}
